-- Forward-only repair for the project-scoped schema that was previously edited into 0001 after it had already been applied.
PRAGMA defer_foreign_keys = on;
ALTER TABLE projects RENAME TO projects_before_0005;
CREATE TABLE projects (id TEXT PRIMARY KEY, org_id TEXT NOT NULL, name TEXT NOT NULL, jurisdiction TEXT, retention_days INTEGER NOT NULL DEFAULT 30, sample_rate REAL NOT NULL DEFAULT 1.0, allowed_origins TEXT NOT NULL, mask_policy_version INTEGER NOT NULL DEFAULT 1, mask_rules TEXT NOT NULL DEFAULT '[]', capture_toggles TEXT NOT NULL DEFAULT '{"heatmaps":false,"console":false,"network":false,"canvas":false}', quota_state TEXT NOT NULL DEFAULT 'ok', config_version INTEGER NOT NULL DEFAULT 1, created_at INTEGER NOT NULL);
INSERT INTO projects (id, org_id, name, jurisdiction, retention_days, sample_rate, allowed_origins, mask_policy_version, mask_rules, capture_toggles, quota_state, config_version, created_at) SELECT id, org_id, name, jurisdiction, retention_days, sample_rate, allowed_origins, mask_policy_version, mask_rules, capture_toggles, quota_state, config_version, created_at FROM projects_before_0005;
DROP TABLE projects_before_0005;
ALTER TABLE sessions RENAME TO sessions_before_0005;
CREATE TABLE sessions (session_id TEXT NOT NULL, project_id TEXT NOT NULL, org_id TEXT NOT NULL, started_at INTEGER NOT NULL, ended_at INTEGER NOT NULL, duration_ms INTEGER NOT NULL, country TEXT, region TEXT, city TEXT, device TEXT, browser TEXT, os TEXT, entry_url TEXT, url_count INTEGER NOT NULL DEFAULT 0, page_count INTEGER, analytics_version INTEGER NOT NULL DEFAULT 0, max_scroll_depth INTEGER, quick_backs INTEGER, interaction_time_ms INTEGER, clicks INTEGER NOT NULL DEFAULT 0, errors INTEGER NOT NULL DEFAULT 0, rages INTEGER NOT NULL DEFAULT 0, navs INTEGER NOT NULL DEFAULT 0, bytes INTEGER NOT NULL DEFAULT 0, segment_count INTEGER NOT NULL DEFAULT 0, flags INTEGER NOT NULL DEFAULT 0, manifest_key TEXT NOT NULL, expires_at INTEGER NOT NULL, PRIMARY KEY (project_id, session_id));
INSERT INTO sessions (session_id, project_id, org_id, started_at, ended_at, duration_ms, country, region, city, device, browser, os, entry_url, url_count, page_count, analytics_version, max_scroll_depth, quick_backs, interaction_time_ms, clicks, errors, rages, navs, bytes, segment_count, flags, manifest_key, expires_at) SELECT session_id, project_id, org_id, started_at, ended_at, duration_ms, country, region, city, device, browser, os, entry_url, url_count, page_count, analytics_version, max_scroll_depth, quick_backs, interaction_time_ms, clicks, errors, rages, navs, bytes, segment_count, flags, manifest_key, expires_at FROM sessions_before_0005;
DROP TABLE sessions_before_0005;
CREATE INDEX idx_sessions_project_time ON sessions(project_id, started_at DESC);
CREATE INDEX idx_sessions_expiry ON sessions(expires_at);
CREATE INDEX idx_sessions_project_country_time ON sessions(project_id, country, started_at DESC, session_id DESC);
CREATE INDEX idx_sessions_project_region_time ON sessions(project_id, region, started_at DESC, session_id DESC);
CREATE INDEX idx_sessions_project_device_time ON sessions(project_id, device, started_at DESC, session_id DESC);
CREATE INDEX idx_sessions_project_browser_time ON sessions(project_id, browser, started_at DESC, session_id DESC);
CREATE INDEX idx_sessions_project_os_time ON sessions(project_id, os, started_at DESC, session_id DESC);
CREATE INDEX idx_sessions_project_entry_url_time ON sessions(project_id, entry_url, started_at DESC, session_id DESC);
CREATE INDEX idx_sessions_project_errors_time ON sessions(project_id, errors, started_at DESC, session_id DESC);
CREATE INDEX idx_sessions_project_duration_time ON sessions(project_id, duration_ms, started_at DESC, session_id DESC);
CREATE INDEX idx_sessions_project_rages_time ON sessions(project_id, rages, started_at DESC, session_id DESC);
CREATE INDEX idx_sessions_project_quick_backs_time ON sessions(project_id, quick_backs, started_at DESC, session_id DESC);
CREATE INDEX idx_sessions_project_analytics_version_time ON sessions(project_id, analytics_version, started_at DESC, session_id DESC);
ALTER TABLE session_events RENAME TO session_events_before_0005;
CREATE TABLE session_events (project_id TEXT NOT NULL, session_id TEXT NOT NULL, t INTEGER NOT NULL, kind TEXT NOT NULL, detail TEXT, PRIMARY KEY (project_id, session_id, t, kind));
INSERT INTO session_events (project_id, session_id, t, kind, detail) SELECT s.project_id, e.session_id, e.t, e.kind, e.detail FROM session_events_before_0005 e INNER JOIN sessions s ON s.session_id = e.session_id;
DROP TABLE session_events_before_0005;
CREATE TABLE IF NOT EXISTS session_deletions (project_id TEXT NOT NULL, session_id TEXT NOT NULL, requested_at INTEGER NOT NULL, attempts INTEGER NOT NULL DEFAULT 0, last_error TEXT, PRIMARY KEY (project_id, session_id));
PRAGMA optimize;
